// ClassifyReviewError maps a reviewer error and partial result into one of the
// four FEAT-022 §12 taxonomy classes. Resolution order:
//  1. reviewRes.Error if it's already one of the canonical class identifiers
//     (the reviewer set it explicitly — preferred path).
//  2. The error string text (for backwards-compatible reviewers that only
//     embed the class in their message).
//  3. ErrReviewVerdictUnparseable as a fallback when the strict-parse error
//     leaks through a reviewer that did not set Error.
//  4. Default to transport (network/provider-side failure) when nothing else
//     matches.
func ClassifyReviewError(reviewErr error, reviewRes *ReviewResult) string {
	if reviewRes != nil {
		switch reviewRes.Error {
		case evidence.OutcomeReviewContextOverflow,
			evidence.OutcomeReviewProviderEmpty,
			evidence.OutcomeReviewUnparseable,
			evidence.OutcomeReviewTransport,
			evidence.OutcomeReviewCostCapExceeded,
			evidence.OutcomeReviewReviewerUnavailable:
			return reviewRes.Error
		}
	}
	msg := ""
	if reviewErr != nil {
		msg = reviewErr.Error()
	}
	switch {
	case strings.Contains(msg, evidence.OutcomeReviewContextOverflow):
		return evidence.OutcomeReviewContextOverflow
	case strings.Contains(msg, evidence.OutcomeReviewCostCapExceeded):
		return evidence.OutcomeReviewCostCapExceeded
	case strings.Contains(msg, evidence.OutcomeReviewReviewerUnavailable):
		return evidence.OutcomeReviewReviewerUnavailable
	case strings.Contains(msg, evidence.OutcomeReviewProviderEmpty):
		return evidence.OutcomeReviewProviderEmpty
	case strings.Contains(msg, evidence.OutcomeReviewUnparseable):
		return evidence.OutcomeReviewUnparseable
	case strings.Contains(msg, evidence.OutcomeReviewTransport):
		return evidence.OutcomeReviewTransport
	case reviewErr != nil && strings.Contains(msg, ErrReviewVerdictUnparseable.Error()):
		return evidence.OutcomeReviewUnparseable
	}
	return evidence.OutcomeReviewTransport
}

// reResultRevField extracts the result_rev value from a structured review-error
// event body (one `result_rev=<sha>` line per event, written by
// reviewErrorEventBody). The format is intentionally line-oriented so it
// survives the AppendEvent body cap without losing the rev association.
var reResultRevField = regexp.MustCompile(`(?m)^result_rev=([^\s]+)\s*$`)
var reReviewerIndexField = regexp.MustCompile(`(?m)^reviewer_index=([0-9]+)\s*$`)

// CountPriorReviewErrors returns the number of `review-error` events already
// recorded against this bead whose body cites the given result_rev. This is
// the FEAT-022 §14 retry counter — it is event-scoped (no separate counter
// field on the bead) so a fresh result_rev naturally resets the count.
func CountPriorReviewErrors(store ExecuteBeadLoopStore, beadID, resultRev string) int {
	if resultRev == "" {
		return 0
	}
	events, err := store.Events(beadID)
	if err != nil {
		return 0
	}
	n := 0
	for _, ev := range events {
		if ev.Kind != "review-error" {
			continue
		}
		m := reResultRevField.FindStringSubmatch(ev.Body)
		if m == nil {
			continue
		}
		if m[1] == resultRev {
			n++
		}
	}
	return n
}

// CountPriorReviewErrorsForSlot is the two-slot review-group retry counter.
// It scopes retry budget to the candidate result_rev and reviewer slot so a
// malformed/empty/transport failure in one slot does not consume the other
// slot's retry allowance.
func CountPriorReviewErrorsForSlot(store ExecuteBeadLoopStore, beadID, resultRev string, reviewerIndex int) int {
	if resultRev == "" {
		return 0
	}
	events, err := store.Events(beadID)
	if err != nil {
		return 0
	}
	wantIndex := fmt.Sprintf("%d", reviewerIndex)
	n := 0
	for _, ev := range events {
		if ev.Kind != "review-error" {
			continue
		}
		rev := reResultRevField.FindStringSubmatch(ev.Body)
		if rev == nil || rev[1] != resultRev {
			continue
		}
		idx := reReviewerIndexField.FindStringSubmatch(ev.Body)
		if idx == nil || idx[1] != wantIndex {
			continue
		}
		n++
	}
	return n
}

// ReviewErrorEventBody is the canonical body shape for review-error and
// review-manual-required events. It carries the failure class, attempt count,
// and result_rev as discrete lines so operators can grep without parsing the
// full reviewer error text. The trailing free-form message is the raw
// reviewer-error string for forensics.
func ReviewErrorEventBody(class string, attemptCount int, resultRev, message string) string {
	var b strings.Builder
	fmt.Fprintf(&b, "failure_class=%s\n", class)
	fmt.Fprintf(&b, "attempt_count=%d\n", attemptCount)
	fmt.Fprintf(&b, "result_rev=%s\n", resultRev)
	if message != "" {
		b.WriteString("\n")
		b.WriteString(message)
	}
	return b.String()
}

func ReviewErrorEventBodyForSlot(class string, attemptCount int, resultRev string, reviewerIndex int, message string) string {
	var b strings.Builder
	fmt.Fprintf(&b, "failure_class=%s\n", class)
	fmt.Fprintf(&b, "attempt_count=%d\n", attemptCount)
	fmt.Fprintf(&b, "result_rev=%s\n", resultRev)

package agent

import (
	"encoding/json"
	"errors"
	"fmt"
	"strings"
)

// ReviewVerdictSchemaVersion is the current schema version for the
// machine-readable reviewer contract emitted as the model's final response.
const ReviewVerdictSchemaVersion = 1

// Finding is one item in ReviewVerdict.Findings — a single review comment
// with severity, free-text summary, and an optional location pointer
// ("path:line"). Severity must be one of "info", "warn", "block".
type Finding struct {
	Severity string `json:"severity,omitempty"`
	Summary  string `json:"summary,omitempty"`
	Location string `json:"location,omitempty"`
}

// ReviewVerdict is the parsed JSON contract emitted by the reviewer agent.
// It replaces the markdown extractor that silently mis-parsed `### Verdict:
// APPROVE` outputs whenever the model echoed the prompt's options-header
// line (the upstream-report regression). The parser is strict: unknown
// verdict values, missing verdict field, and truncated/unfenced JSON all
// surface as ErrReviewVerdictUnparseable.
type ReviewVerdict struct {
	SchemaVersion int        `json:"schema_version,omitempty"`
	Verdict       Verdict    `json:"verdict"`
	Summary       string     `json:"summary,omitempty"`
	PerAC         []ReviewAC `json:"per_ac,omitempty"`
	Findings      []Finding  `json:"findings,omitempty"`
	ProseFindings []Finding  `json:"prose_findings,omitempty"`
}

// ErrReviewVerdictUnparseable is the sentinel returned by ParseReviewVerdict
// when the reviewer output cannot be decoded into a valid ReviewVerdict.
// The work classifies it as evidence.OutcomeReviewUnparseable
// (retryable review-error) rather than mis-recording a BLOCK verdict.
var ErrReviewVerdictUnparseable = errors.New("reviewer output: unparseable JSON verdict")

// ParseReviewVerdict decodes a reviewer agent's raw output into a
// ReviewVerdict. It accepts:
//   - raw JSON object;
//   - a single ```json …``` fenced block;
//   - mixed prose and fenced blocks where the LAST ```json block is the
//     verdict.
//
// It rejects:
//   - empty input;
//   - inputs containing no JSON object at all;
//   - JSON missing the "verdict" field;
//   - unknown verdict values (anything other than APPROVE,
//     REQUEST_CHANGES, BLOCK);
//   - truncated/malformed JSON.
//
// Unknown fields outside the schema are tolerated (forward-compat).
func ParseReviewVerdict(raw []byte) (ReviewVerdict, error) {
	if len(strings.TrimSpace(string(raw))) == 0 {
		return ReviewVerdict{}, fmt.Errorf("%w: empty input", ErrReviewVerdictUnparseable)
	}
	candidate, ok := extractJSONCandidate(string(raw))
	if !ok {
		return ReviewVerdict{}, fmt.Errorf("%w: no JSON object found", ErrReviewVerdictUnparseable)
	}

	// First decode into a generic shape so we can validate the verdict
	// field's presence and value before binding to ReviewVerdict.
	var probe map[string]json.RawMessage
	if err := json.Unmarshal([]byte(candidate), &probe); err != nil {
		return ReviewVerdict{}, fmt.Errorf("%w: %v", ErrReviewVerdictUnparseable, err)
	}
	rawVerdict, ok := probe["verdict"]
	if !ok {
		return ReviewVerdict{}, fmt.Errorf("%w: missing verdict field", ErrReviewVerdictUnparseable)
	}
	var verdictStr string
	if err := json.Unmarshal(rawVerdict, &verdictStr); err != nil {
		return ReviewVerdict{}, fmt.Errorf("%w: verdict not a string: %v", ErrReviewVerdictUnparseable, err)
	}
	switch Verdict(verdictStr) {
	case VerdictApprove, VerdictRequestChanges, VerdictBlock, VerdictRequestClarification:
	default:
		return ReviewVerdict{}, fmt.Errorf("%w: unknown verdict %q", ErrReviewVerdictUnparseable, verdictStr)
	}

	var rv ReviewVerdict
	if err := json.Unmarshal([]byte(candidate), &rv); err != nil {
		return ReviewVerdict{}, fmt.Errorf("%w: %v", ErrReviewVerdictUnparseable, err)
	}
	return rv, nil
}

// extractJSONCandidate returns the JSON object payload from a raw reviewer
// output. Resolution order:
//  1. The last ```json … ``` fenced block (handles models that wrap output).
//  2. The last ``` … ``` fenced block when its body parses as a JSON object.
//  3. The substring from the first '{' that balances braces (handles raw
//     JSON or JSON with leading prose).
//
// Returns ok=false when no plausible JSON object is found.
func extractJSONCandidate(s string) (string, bool) {
	if c, ok := lastFencedBlock(s, "json"); ok {
		return strings.TrimSpace(c), true
	}
	if c, ok := lastFencedBlock(s, ""); ok {
		trimmed := strings.TrimSpace(c)
		if strings.HasPrefix(trimmed, "{") {
			return trimmed, true
		}
	}
	if c, ok := firstBalancedObject(s); ok {
		return c, true
	}
	return "", false
}

// lastFencedBlock returns the body of the LAST ```<lang> … ``` fenced block
// in s. lang="" matches any fence ("``` … ```"). Returns ok=false when no
// matching fence is found or the fence is unterminated.
func lastFencedBlock(s, lang string) (string, bool) {
	open := "```"
	if lang != "" {
		open = "```" + lang
	}
	var found string
	var ok bool
	idx := 0
	for {
		i := indexFromAny(s, idx, open)
		if i < 0 {
			break
		}
		// Ensure the fence is followed by newline or whitespace (avoid
		// matching ```jsonc when looking for ```json).
		afterOpen := i + len(open)
		if afterOpen < len(s) {
			c := s[afterOpen]
			if lang != "" && c != '\n' && c != '\r' && c != ' ' && c != '\t' {
				idx = i + len(open)
				continue
			}
		}
		bodyStart := afterOpen
		// Skip a single trailing newline after the opening fence.
		if bodyStart < len(s) && s[bodyStart] == '\n' {
			bodyStart++
		} else if bodyStart+1 < len(s) && s[bodyStart] == '\r' && s[bodyStart+1] == '\n' {
			bodyStart += 2
		}
		// Find closing fence.
		j := strings.Index(s[bodyStart:], "```")
		if j < 0 {
			break
		}
		body := s[bodyStart : bodyStart+j]
		// Strip a single trailing newline before the closing fence.
		body = strings.TrimRight(body, "\n\r")
		found = body
		ok = true
		idx = bodyStart + j + 3
	}
	return found, ok
}

// indexFromAny is strings.Index but starting at the given offset.
func indexFromAny(s string, from int, sub string) int {
	if from >= len(s) {
		return -1
	}
	i := strings.Index(s[from:], sub)
	if i < 0 {
		return -1
	}
	return from + i
}

// firstBalancedObject scans for the first '{' in s and returns the substring
// that closes its outermost JSON object, respecting strings and escapes.
// Returns ok=false on no opening brace or on an unterminated object.
func firstBalancedObject(s string) (string, bool) {
	start := strings.Index(s, "{")
	if start < 0 {
		return "", false
	}
	depth := 0
	inString := false
	escape := false
	for i := start; i < len(s); i++ {
		c := s[i]
		if escape {
			escape = false
			continue
		}
		if inString {
			switch c {
			case '\\':
				escape = true
			case '"':
				inString = false
			}
			continue
		}
		switch c {
		case '"':
			inString = true
		case '{':
			depth++
		case '}':
			depth--
			if depth == 0 {
				return s[start : i+1], true
			}
		}
	}
	return "", false
}

