func appendWorkEvent(store BeadEventAppender, beadID, kind, summary string, body map[string]any, actor string, at time.Time) {
	if store == nil || beadID == "" {
		return
	}
	encodedBody, err := json.Marshal(body)
	if err != nil {
		return
	}
	_ = store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      kind,
		Summary:   summary,

		ProjectRoot: projectRoot,
		BeadStore:   store,
		Runner:      runner,
	}

	res, err := reviewer.Review(context.Background(), projectRoot, CandidateResult{
		Report: ExecuteBeadReport{
			BeadID:    "ddx-review-happy",
			AttemptID: "attempt-preland-worktree",
			Status:    ExecuteBeadStatusSuccess,
			BaseRev:   baseRev,
